sys_ui_policy.script_true:
function onCondition() {
	//RJ - STRY0065465 - Template fields in parity with task
	//onLoad: This UI Policy takes care of hiding fields based on tasker_type.
	//Check Task - Tasker type onChange hide fields -- client script to modify the form view when the tasker_type changes
	//HT stories STRY0052946 and STRY0052946 hide form fields if tasker type = Information only OR Acknowledgement
	// DFCT0010845 - When changing the "Tasker Type" to "Acknowledgement" or "Information Only" on a "Template" and "Template Task" most of the "Duration" section disappears
	g_form.setDisplay("duration", false);
	// STRY0110317 
	//g_form.setDisplay("u_duration_days", false);
	//g_form.setDisplay("u_duration_time_due", false);

	//Assignment fields
	g_form.setDisplay("u_reviewer", false);
	//Risk section
	g_form.setSectionDisplay('risk', false);

}
